from flask import Flask, request, jsonify
from collections import defaultdict

app = Flask(__name__)

# In-memory storage for annotations and images
annotations = defaultdict(list)
images = {}

def majority_vote(labels):
    from collections import Counter
    label_counts = Counter(labels)
    most_common_label, _ = label_counts.most_common(1)[0]
    return most_common_label

@app.route('/label', methods=['POST'])
def receive_label():
    data = request.get_json()
    image_id = data['image_id']
    label = data['label']
    
    if image_id not in images:
        images[image_id] = None  # Placeholder for the actual image data
    
    annotations[image_id].append(label)
    
    return jsonify({"message": "Label received successfully"}), 200

@app.route('/train', methods=['POST'])
def train_model():
    import pandas as pd
    from sklearn.svm import SVC

    df = pd.DataFrame([(image_id, majority_vote(labels)) for image_id, labels in annotations.items()])
    df.columns = ['image_id', 'label']
    
    # Assuming you have a function to extract features from images
    def extract_features(image):
        # Placeholder for feature extraction logic
        return [0.1, 0.2, 0.3]  # Example feature vector
    
    X = df['image_id'].apply(lambda image_id: extract_features(images[image_id])).tolist()
    y = df['label'].tolist()
    
    model = SVC()
    model.fit(X, y)
    
    return jsonify({"message": "Model trained successfully"}), 200

if __name__ == '__main__':
    app.run(debug=True)